#!/usr/bin/env python3
# rollout_watchdog.py — polls Alertmanager and executes automated rollbacks
import sys, time, requests, subprocess, logging

logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(message)s")
log = logging.getLogger("rollout-watchdog")

ALERTMANAGER_URL = "http://alertmanager:9093"
ROLLOUT_NAME = "claude-gateway"
NAMESPACE = "claude-api"
POLL_INTERVAL = 15  # seconds

def get_active_alerts() -> list[dict]:
    r = requests.get(f"{ALERTMANAGER_URL}/api/v2/alerts", params={"active": True}, timeout=5)
    r.raise_for_status()
    return r.json()

def is_rollback_alert(alert: dict) -> bool:
    labels = alert.get("labels", {})
    return labels.get("action") == "rollback" and labels.get("severity") == "p0"

def execute_rollback(alert: dict):
    summary = alert.get("annotations", {}).get("summary", "unknown")
    log.warning(f"P0 rollback trigger: {summary}")
    result = subprocess.run(
        ["kubectl", "argo", "rollouts", "abort", ROLLOUT_NAME, "-n", NAMESPACE],
        capture_output=True, text=True
    )
    if result.returncode == 0:
        log.info(f"Rollback executed successfully")
        notify_pagerduty(f"Automated rollback: {summary}")
    else:
        log.error(f"Rollback failed: {result.stderr}")
        notify_pagerduty(f"Rollback FAILED — manual action required: {summary}", severity="critical")

def notify_pagerduty(message: str, severity: str = "warning"):
    # PagerDuty Events API v2
    payload = {
        "routing_key": get_pd_routing_key(),
        "event_action": "trigger",
        "payload": {
            "summary": message,
            "severity": severity,
            "source": "rollout-watchdog",
        }
    }
    requests.post("https://events.pagerduty.com/v2/enqueue", json=payload, timeout=5)

def main():
    log.info(f"Watchdog started. Polling every {POLL_INTERVAL}s.")
    while True:
        try:
            alerts = get_active_alerts()
            for alert in alerts:
                if is_rollback_alert(alert):
                    execute_rollback(alert)
                    sys.exit(0)   # one rollback per run; restart clears state
        except Exception as e:
            log.error(f"Watchdog error: {e}")
        time.sleep(POLL_INTERVAL)

if __name__ == "__main__":
    main()
